INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a2d10900-0000-4000-8000-000000000000','a2d00000-0000-4000-8000-000000000000','確認テスト ─ 財務三表を読む','quiz',NULL,NULL,NULL,3,2),
  ('a2d20900-0000-4000-8000-000000000000','a2d00000-0000-4000-8000-000000000000','確認テスト ─ 損益分岐点と原価管理','quiz',NULL,NULL,NULL,3,4),
  ('a2d30900-0000-4000-8000-000000000000','a2d00000-0000-4000-8000-000000000000','確認テスト ─ 投資判断の基礎','quiz',NULL,NULL,NULL,3,6),
  ('a2d40900-0000-4000-8000-000000000000','a2d00000-0000-4000-8000-000000000000','確認テスト ─ 資金繰りの基本','quiz',NULL,NULL,NULL,3,8)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a2d10900-0000-4000-8000-000000000000','財務三表の本質を、一行で言うとどれか。','会社という一つの実態を、三つの角度から写したものである','三つの独立した会社を、それぞれ別々に記録したものである','経営者の意思決定を時系列で記録したものである','利益の増減だけを三つの方法で計算したものである','A',0),
('a2d10900-0000-4000-8000-000000000000','貸借対照表が映す本質として、本文が最も重視するのはどれか。','持っているものの一覧、すなわち資産の多さ','現金が一年でどう出入りしたかの流れ','持っているものを、どう賄ったか(負債か純資産か)','本業でいくら稼ぎ、いくら残したか','C',1),
('a2d10900-0000-4000-8000-000000000000','本文が挙げる「三表のつながり」の二つはどれか。','利益が現金に必ず一致し、資産が負債に等しくなる','利益が純資産に積もり、利益と現金の動きはズレる','売上が資産に積もり、費用が負債に積もる','営業CFが投資CFに等しく、財務CFがゼロになる','B',2),
('a2d20900-0000-4000-8000-000000000000','損益分岐点を、一行で言うとどれか。','変動費がちょうどゼロになる売上の高さ','利益がちょうどゼロになる、売上の高さ','固定費が限界利益を上回る売上の高さ','限界利益が最大になる売上の高さ','B',0),
('a2d20900-0000-4000-8000-000000000000','本文の定義で、限界利益とはどれか。','売上から固定費だけを引いたもの','売上から固定費と変動費の両方を引いたもの','売上から変動費だけを引いたもの','ぎりぎり赤字にならない最低限の利益','C',1),
('a2d20900-0000-4000-8000-000000000000','損益分岐点売上を求める式として、本文が示すのはどれか。','固定費 ÷ 限界利益率','変動費 ÷ 限界利益率','固定費 × 限界利益率','売上 − 変動費 − 固定費','A',2),
('a2d30900-0000-4000-8000-000000000000','投資判断の本質を、一行で言うとどれか。','どこかにある正解を外さず当てる作業である','今出すお金が、将来どれだけの価値を生むかを見積もる作業である','金額が高いか安いかを、その場で見極める作業である','過去に使った額を回収しきる作業である','B',0),
('a2d30900-0000-4000-8000-000000000000','本文が示す回収期間の求め方はどれか。','投資額 ÷ 年あたりの効果','年あたりの効果 ÷ 投資額','効果 ÷ 投資額 × 100','投資額 × 限界利益率','A',1),
('a2d30900-0000-4000-8000-000000000000','失敗④「サンクコストに引きずられる」の修正として、本文が示すのはどれか。','これまでいくら使ったかを基準に、続けるか決める','すでに投じた額が大きいほど、続ける価値も高いと考える','過去ではなく、これから先の出すお金と戻るお金だけで判断する','損を確定させないため、追加投資で挽回を図る','C',2),
('a2d40900-0000-4000-8000-000000000000','資金繰りの本質を、一行で言うとどれか。','会社が利益を最大化するように費用を配分することである','会社が現金を切らさないように、入りと出のタイミングを先読みすることである','過去の現金の出入りを、正確に記録することである','各チームの利益を足し合わせて手元残高を出すことである','B',0),
('a2d40900-0000-4000-8000-000000000000','黒字でも現金が尽きて会社が止まることを、本文は何と呼ぶか。','運転資金ショート','現金化サイクルの断絶','黒字倒産','季節変動リスク','C',1),
('a2d40900-0000-4000-8000-000000000000','本文が挙げる「現金を作る打ち手の四つの方向」に含まれないのはどれか。','入りを、早くする','出を、平準化する','眠った現金を、起こす','売上目標を、引き上げる','D',2);
