-- a2d00000-0000-4000-8000-000000000000 動画別3問クイズ + 既存コース末(a2d90000-0000-4000-8000-000000000000)を末尾へ  自動生成
UPDATE public.lessons SET sort_order=1 WHERE id='a2d10000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=3 WHERE id='a2d20000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=5 WHERE id='a2d30000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=7 WHERE id='a2d40000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=99 WHERE id='a2d90000-0000-4000-8000-000000000000';

ON CONFLICT (id) DO UPDATE SET course_id=EXCLUDED.course_id,title=EXCLUDED.title,content_type=EXCLUDED.content_type,estimated_minutes=EXCLUDED.estimated_minutes,sort_order=EXCLUDED.sort_order;

DELETE FROM public.quiz_questions WHERE lesson_id IN ('a2d10900-0000-4000-8000-000000000000','a2d20900-0000-4000-8000-000000000000','a2d30900-0000-4000-8000-000000000000','a2d40900-0000-4000-8000-000000000000');

